// // This counter decrements from 15 to 0 on each positive clock edge and resets to 16 when a synchronous active high reset signal is asserted.
module up_counter (
  input clk,
  input reset,
  output reg [3:0] count);always @(posedge clk) begin
    if (reset) count <= 4'b0000;
    else count <= count + 1;
end

endmodule
